function computer_details_table_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('computer_details_table');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'pc_number' => Request::val('pc_number', ''),
		'pc_hostname' => Request::val('pc_hostname', ''),
		'pc_mac_address' => Request::val('pc_mac_address', ''),
		'pc_static_ip' => Request::val('pc_static_ip', ''),
		'room_number' => Request::val('room_number', ''),
		'maintained_by' => Request::val('maintained_by', ''),
		'assigned_to_user' => Request::val('assigned_to_user', ''),
		'remote_access' => Request::val('remote_access', ''),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('computer_details_table', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		computer_details_table_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function computer_details_table_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

