function computer_details_table_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('computer_details_table', $selected_id, 'edit')) return false;

	$data = [
		'pc_number' => Request::val('pc_number', ''),
		'pc_hostname' => Request::val('pc_hostname', ''),
		'pc_mac_address' => Request::val('pc_mac_address', ''),
		'pc_static_ip' => Request::val('pc_static_ip', ''),
		'room_number' => Request::val('room_number', ''),
		'maintained_by' => Request::val('maintained_by', ''),
		'assigned_to_user' => Request::val('assigned_to_user', ''),
		'remote_access' => Request::val('remote_access', ''),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('computer_details_table', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: computer_details_table_before_update
	if(function_exists('computer_details_table_before_update')) {
		$args = ['old_data' => $old_data];
		if(!computer_details_table_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'computer_details_table',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="computer_details_table_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('computer_details_table', $data['selectedID'], calculated_fields()['computer_details_table']);

	// hook: computer_details_table_after_update
	if(function_exists('computer_details_table_after_update')) {
		if($row = getRecord('computer_details_table', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!computer_details_table_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('computer_details_table', $selected_id);
}

